import React from 'react';
import './About.css';
import { FadeTransition } from './PageTransition';

const About = () => {
  const skills = [
    { category: 'Frontend', items: ['React', 'JavaScript', 'HTML5', 'CSS3'] },
    { category: 'Backend', items: ['Node.js', 'ExpressJS', 'SQL', 'MongoDB'] },
    { category: 'Tools', items: ['Git', 'Docker', 'AWS', 'VS Code'] },
    { category: 'Programming', items: ['Python', 'Java', 'C++', 'C'] },
    { category: 'Operating Systems', items: ['Windows', 'Linux', 'Ubuntu', 'Mac'] },
    { category: 'Other', items: ['REST APIs', 'Agile', 'UI/UX', 'Testing'] }
  ];

  return (
    <FadeTransition>
      <section className="about section">
        <div className="container">
          <h2 className="section-title">About Me</h2>
          <div className="about-content">
            <div className="about-text">
              <p>
                I am a Computer Science graduate student at the University of Missouri-Columbia, specializing in 
                Cybersecurity, AI/ML, and Full Stack Development. With a strong foundation in both theoretical 
                concepts and practical applications, I blend security expertise with innovative development practices 
                to create robust, secure solutions.
              </p>
              <p>
                My professional journey spans across diverse roles - from conducting security assessments and 
                penetration testing as a Cybersecurity Analyst to developing machine learning models for power 
                loss estimation as a Research Assistant. This unique combination allows me to approach problems 
                with a comprehensive perspective, considering both security implications and technological innovation.
              </p>
              <p>
                Currently, I'm focused on advancing my research in machine learning applications while maintaining 
                my passion for cybersecurity. I thrive on challenges that require creative problem-solving and 
                am constantly exploring new technologies to enhance my skill set. Whether it's developing secure 
                web applications or implementing AI solutions, I'm committed to delivering high-quality results 
                that make a meaningful impact.
              </p>
            </div>
            <div className="skills-grid">
              {skills.map((skillGroup, index) => (
                <div key={index} className="skill-category">
                  <h3 className="skill-category-title">{skillGroup.category}</h3>
                  <ul className="skill-list">
                    {skillGroup.items.map((skill, skillIndex) => (
                      <li key={skillIndex} className="skill-item">
                        {skill}
                      </li>
                    ))}
                  </ul>
                </div>
              ))}
            </div>
          </div>
        </div>
      </section>
    </FadeTransition>
  );
};

export default About;
